def convert_infinities_to_markers(obj): return utils.convert_infinities_to_markers(obj)
def convert_infinity_markers(obj): return utils.convert_infinity_markers(obj)

def _migrate_old_file_structure():
    """One-time migration from the legacy 'files/' folder to the new folder layout.

    Explicit files:
      files/config.json          → config/config.json
      files/cache_metadata.json  → themes_cache/cache_metadata.json
      files/censors.json         → censors/censors.json
      files/ramuns_censors.json  → censors/ramuns_censors.json

    All *.json files in files/ ending with 'rules.json' (case-insensitive) → rules/

    After migration, removes 'files/' if it is empty.

    Preset migration (saved_lightning_mode_settings / saved_infinite_settings) always
    runs against config/config.json so it works even if files/ was already removed.
    """
    if os.path.exists("files"):
        explicit = [
            (os.path.join("files", "config.json"),         CONFIG_FILE),
            (os.path.join("files", "cache_metadata.json"), CACHE_METADATA_FILE),
            (os.path.join("files", "censors.json"),        CENSOR_JSON_FILE),
            (os.path.join("files", "ramuns_censors.json"), os.path.join(CENSORS_FOLDER, "ramuns_censors.json")),
        ]
        for src, dst in explicit:
            if os.path.exists(src) and not os.path.exists(dst):
                os.makedirs(os.path.dirname(dst) or ".", exist_ok=True)
                os.replace(src, dst)
                print(f"Migrated {src} → {dst}")

        # Move all rules files (any *.json ending with 'rules.json') to rules/
        try:
            for fname in os.listdir("files"):
                if fname.lower().endswith("rules.json") and os.path.isfile(os.path.join("files", fname)):
                    dst = os.path.join(RULES_FOLDER, fname)
                    if not os.path.exists(dst):
                        os.makedirs(RULES_FOLDER, exist_ok=True)
                        os.replace(os.path.join("files", fname), dst)
                        print(f"Migrated files/{fname} → {dst}")
        except Exception as e:
            print(f"Warning: rules migration error: {e}")

        # Remove files/ if now empty (ignoring subdirectories)
        try:
            remaining = [f for f in os.listdir("files") if os.path.isfile(os.path.join("files", f))]
            if not remaining:
                # Only remove the folder itself if there are no subdirectories either
                if not any(os.path.isdir(os.path.join("files", d)) for d in os.listdir("files")):
                    os.rmdir("files")
                    print("Removed empty 'files/' folder.")
        except Exception:
            pass

    # Migrate saved_lightning_mode_settings and saved_infinite_settings from config.json.
    # This runs unconditionally so it works even when files/ was already removed in a prior run.
    try:
        if os.path.exists(CONFIG_FILE):
            with open(CONFIG_FILE, "r", encoding="utf-8") as f:
                old_config = json.load(f)
            for name, diff in old_config.get("saved_lightning_mode_settings", {}).items():
                dst = os.path.join(LIGHTNING_SETTINGS_FOLDER, f"{name}.json")
                if not os.path.exists(dst):
                    os.makedirs(LIGHTNING_SETTINGS_FOLDER, exist_ok=True)
                    with open(dst, "w", encoding="utf-8") as f:
                        json.dump(diff, f, indent=4)
                    print(f"Migrated lightning preset '{name}' \u2192 {dst}")
            for name, diff in old_config.get("saved_infinite_settings", {}).items():
                dst = os.path.join(INFINITE_SETTINGS_FOLDER, f"{name}.json")
                if not os.path.exists(dst):
                    os.makedirs(INFINITE_SETTINGS_FOLDER, exist_ok=True)
                    with open(dst, "w", encoding="utf-8") as f:
                        json.dump(diff, f, indent=4)
                    print(f"Migrated infinite preset '{name}' \u2192 {dst}")
    except Exception as e:
        print(f"Warning: preset migration error: {e}")

def _migrate_playlist_names():
    """Rename legacy system playlist files: 'Peek Themes' → 'Reveal Themes',
    'Mute Peek Themes' → 'Mute Reveal Themes'."""
    renames = [
        ("Peek Themes.json",      "Reveal Themes.json"),
        ("Mute Peek Themes.json", "Mute Reveal Themes.json"),
    ]
    for old_name, new_name in renames:
        old_path = os.path.join(PLAYLISTS_FOLDER, old_name)
        new_path = os.path.join(PLAYLISTS_FOLDER, new_name)
        if os.path.exists(old_path) and not os.path.exists(new_path):
            try:
                os.replace(old_path, new_path)
                print(f"Migrated playlist '{old_name}' \u2192 '{new_name}'")
            except Exception as e:
                print(f"Warning: could not rename playlist '{old_name}': {e}")

def _load_settings_presets(folder): return utils._load_settings_presets(folder)

def _load_popout_layout_presets():
    """Return {name: {layout: [...], columns: N}} for all saved popout layout presets."""
    presets = {}
    if not os.path.exists(POPOUT_LAYOUTS_FOLDER):
        return presets
    for fname in sorted(os.listdir(POPOUT_LAYOUTS_FOLDER)):
        if fname.endswith(".json"):
            name = fname[:-5]
            try:
                with open(os.path.join(POPOUT_LAYOUTS_FOLDER, fname), "r", encoding="utf-8") as f:
                    presets[name] = json.load(f)
            except Exception as e:
                print(f"Failed to load popout layout preset '{fname}': {e}")
    return presets

def _save_popout_layout_preset(name, layout_list, columns):
    """Write a single popout layout preset to POPOUT_LAYOUTS_FOLDER/<name>.json."""
    os.makedirs(POPOUT_LAYOUTS_FOLDER, exist_ok=True)
    path = os.path.join(POPOUT_LAYOUTS_FOLDER, f"{name}.json")
    _atomic_json_write(path, {"layout": layout_list, "columns": columns}, indent=4)

def _atomic_json_write(path, data, **dump_kwargs): return utils._atomic_json_write(path, data, **dump_kwargs)

def _save_settings_presets(folder, saved_dict, default_dict, update_fn=None, convert_inf=False): return utils._save_settings_presets(folder, saved_dict, default_dict, update_fn, convert_inf)

def save_config():
    """Function to save configuration"""
    files_folder = os.path.dirname(CONFIG_FILE)  # Get the folder path

    if not os.path.exists(files_folder):
        os.makedirs(files_folder)
    lightning_diff = compute_settings_diff(lightning_mode_settings_default, lightning_mode_settings) or {}

    _save_settings_presets(LIGHTNING_SETTINGS_FOLDER, saved_lightning_mode_settings,
                           lightning_mode_settings_default, update_fn=update_lightning_mode_settings)
    _save_settings_presets(INFINITE_SETTINGS_FOLDER, saved_infinite_settings,
                           INFINITE_SETTINGS_DEFAULT, convert_inf=True)
    _save_settings_presets(BONUS_SETTINGS_FOLDER, saved_bonus_settings, BONUS_SETTINGS_DEFAULT)

    config = {
        "host": host,
        **{s["config_key"]: globals()[s["key"]] for s in SETTINGS_SCHEMA},
        "color_options": OVERLAY_COLOR_OPTIONS,
        "directory": directory,
        "lightning_mode_settings": lightning_diff,
        "selected_light_mode_settings": selected_light_mode_settings,
        "selected_infinite_settings": selected_infinite_settings,
        "bonus_settings": compute_settings_diff(BONUS_SETTINGS_DEFAULT, bonus_settings) or {},
        "selected_bonus_settings": selected_bonus_settings,
        "popout_layout": popout_layout if popout_layout is not None else [],
        "metadata_last_updated": metadata_last_updated,
        "censors_last_updated": censors_last_updated,
        "scoreboard_version_seen": scoreboard_control.version_seen,
        "popout_columns": popout_columns,
        "shortcuts": globals().get("shortcuts_config", {}),
        "playlist": playlist,
        "directory_files": directory_files,
        "tutorial_shown": globals().get("tutorial_shown", False),
        "set_toggles": {
            "censors_enabled": censors_enabled,
            "censors_nsfw_enabled": censors_nsfw_enabled,
            "auto_info_start": auto_info_start,
            "auto_info_end": auto_info_end,
            "auto_refresh_toggle": auto_refresh_toggle,
            "disable_shortcuts": disable_shortcuts,
            "progress_bar_enabled": progress_bar_enabled,
            "autoplay_fullscreen": autoplay_fullscreen,
            "mpv_always_on_top": mpv_always_on_top,
        },
    }
    
    # Convert infinities and diff infinite_settings against defaults before saving
    if playlist.get("infinite_settings"):
        config["playlist"] = copy.deepcopy(playlist)
        inf_diff = compute_settings_diff(INFINITE_SETTINGS_DEFAULT, config["playlist"]["infinite_settings"]) or {}
        config["playlist"]["infinite_settings"] = convert_infinities_to_markers(inf_diff)
    
    update_current_index(save = False)
    _atomic_json_write(CONFIG_FILE, config, indent=4, allow_nan=False)

def _migrate_theme_flags(filter_dict): utils._migrate_theme_flags(filter_dict)

def load_config():
    """Function to load configuration"""
    global directory_files, directory, playlist, host, inverted_colors, scoreboard_rules
    global metadata_last_updated, censors_last_updated, OVERLAY_COLOR_OPTIONS
    global lightning_mode_settings, selected_light_mode_settings, saved_lightning_mode_settings
    global infinite_settings, selected_infinite_settings, saved_infinite_settings
    global bonus_settings, saved_bonus_settings, selected_bonus_settings
    global INVERSE_OVERLAY_BACKGROUND_COLOR, INVERSE_OVERLAY_TEXT_COLOR, MIDDLE_OVERLAY_BACKGROUND_COLOR
    global stream_instance, ost_stream_instance
    global popout_layout, popout_columns, shortcuts_config
    # Schema settings loaded via config keys below
    global OPENAI_API_KEY, selected_rules_file, OVERLAY_BACKGROUND_COLOR, OVERLAY_TEXT_COLOR, volume_level
    global censors_enabled, auto_info_start, auto_info_end, auto_refresh_toggle, disable_shortcuts, tutorial_shown, keep_set_toggles, progress_bar_enabled, autoplay_fullscreen, mpv_always_on_top, censors_nsfw_enabled
    try:
        if os.path.exists(CONFIG_FILE):
            with open(CONFIG_FILE, "r") as f:
                config = json.load(f)
            # Convert infinity markers back to float('inf')
            config = convert_infinity_markers(config)
            # Load all schema settings
            _type_cast = {"int": int, "float": float, "bool": bool}
            for _s in SETTINGS_SCHEMA:
                _val = config.get(_s["config_key"], _s["default"])
                _cast = _type_cast.get(_s["type"])
                globals()[_s["key"]] = _cast(_val) if _cast else _val
            host = config.get("host", "")
            playlist = config.get("playlist", copy.deepcopy(BLANK_PLAYLIST))
            if playlist.get("infinite_settings") is not None:
                from functools import reduce
                def _deep_merge(base, override):
                    result = copy.deepcopy(base)
                    for k, v in override.items():
                        if isinstance(v, dict) and isinstance(result.get(k), dict):
                            result[k] = _deep_merge(result[k], v)
                        else:
                            result[k] = copy.deepcopy(v)
                    return result
                playlist["infinite_settings"] = _deep_merge(INFINITE_SETTINGS_DEFAULT, playlist["infinite_settings"])
            if "background_track_history" not in playlist:
                playlist["background_track_history"] = []
            _migrate_theme_flags(playlist.get("filter", {}))
            directory_files = config.get("directory_files", {})
            directory = config.get("directory", "themes")
            scoreboard_rules = load_rules(selected_rules_file)
            set_rules()
            lightning_mode_settings = update_lightning_mode_settings(config.get("lightning_mode_settings", copy.deepcopy(lightning_mode_settings_default)))
            selected_light_mode_settings = config.get("selected_light_mode_settings", "")
            saved_lightning_mode_settings = convert_infinity_markers(_load_settings_presets(LIGHTNING_SETTINGS_FOLDER))

            selected_infinite_settings = config.get("selected_infinite_settings", "")
            saved_infinite_settings = convert_infinity_markers(_load_settings_presets(INFINITE_SETTINGS_FOLDER))

            saved_bonus_settings = _load_settings_presets(BONUS_SETTINGS_FOLDER)
            for _bn, _bd in saved_bonus_settings.items():
                saved_bonus_settings[_bn] = sync_with_default(copy.deepcopy(_bd), BONUS_SETTINGS_DEFAULT)
            bonus_settings = sync_with_default(
                copy.deepcopy(config.get("bonus_settings", {})), BONUS_SETTINGS_DEFAULT
            )
            selected_bonus_settings = config.get("selected_bonus_settings", "")
            if selected_bonus_settings and selected_bonus_settings in saved_bonus_settings:
                bonus_settings = copy.deepcopy(saved_bonus_settings[selected_bonus_settings])
            
            inverted_colors = config.get("inverted_colors", False)
            # mpv players do not need per-load recreation
            try:
                set_volume(volume_level)
            except Exception as e:
                pass
            if selected_light_mode_settings and selected_light_mode_settings in saved_lightning_mode_settings:
                # A named template is selected — load it (overrides the inline saved settings)
                lightning_mode_settings = update_lightning_mode_settings(saved_lightning_mode_settings[selected_light_mode_settings])
            
            if selected_infinite_settings and selected_infinite_settings in saved_infinite_settings:
                infinite_settings.clear()
                infinite_settings.update(sync_with_default(copy.deepcopy(saved_infinite_settings[selected_infinite_settings]), INFINITE_SETTINGS_DEFAULT))
            
            if OPENAI_API_KEY:
                set_openai_client_key()
            metadata_fetch.set_credentials(IGDB_CLIENT_ID, IGDB_CLIENT_SECRET)
            cache_download.update_settings(
                themes_cache_size=themes_cache_size,
                auto_download_themes=auto_download_themes,
                app_version=APP_VERSION,
            )
            try:
                update_playlist_name()
                update_current_index()
            except Exception as e:
                pass
            OVERLAY_COLOR_OPTIONS = config.get("color_options", ["black", "white"])
            INVERSE_OVERLAY_BACKGROUND_COLOR = config.get("text_color", "white")
            INVERSE_OVERLAY_TEXT_COLOR = config.get("back_color", "black")
            MIDDLE_OVERLAY_BACKGROUND_COLOR = interpolate_color(OVERLAY_BACKGROUND_COLOR, INVERSE_OVERLAY_BACKGROUND_COLOR, 0.6)
            send_scoreboard_colors()
            metadata_last_updated = config.get("metadata_last_updated", 0)
            censors_last_updated = config.get("censors_last_updated", 0)
            scoreboard_control.version_seen = config.get("scoreboard_version_seen", "")
            # Popout layout — None means "use default"
            _saved_layout = config.get("popout_layout", None)
            popout_layout = _saved_layout if _saved_layout else None  # empty list → None (use default)
            popout_columns = int(config.get("popout_columns", 5))
            shortcuts_config = config.get("shortcuts", {})
            tutorial_shown = config.get("tutorial_shown", False)
            web_server.set_host_password(HOST_PASSWORD)
            if keep_set_toggles:
                _t = config.get("set_toggles", {})
                if "censors_enabled" in _t:
                    censors_enabled = bool(_t["censors_enabled"])
                if "censors_nsfw_enabled" in _t:
                    censors_nsfw_enabled = bool(_t["censors_nsfw_enabled"])
                if "auto_info_start" in _t:
                    auto_info_start = bool(_t["auto_info_start"])
                if "auto_info_end" in _t:
                    auto_info_end = bool(_t["auto_info_end"])
                if "auto_refresh_toggle" in _t:
                    auto_refresh_toggle = bool(_t["auto_refresh_toggle"])
                if "disable_shortcuts" in _t:
                    disable_shortcuts = bool(_t["disable_shortcuts"])
                if "progress_bar_enabled" in _t:
                    progress_bar_enabled = bool(_t["progress_bar_enabled"])
                if "autoplay_fullscreen" in _t:
                    autoplay_fullscreen = bool(_t["autoplay_fullscreen"])
                if "mpv_always_on_top" in _t:
                    mpv_always_on_top = bool(_t["mpv_always_on_top"])
                    try:
                        player._p.ontop = mpv_always_on_top
                    except Exception:
                        pass
    except Exception as e:
        os.remove(CONFIG_FILE)
        print(f"Error loading config: {e}")
        return False
    return False

