def get_light_round_time():
    if fixed_lightning_round_playlist_data and fixed_current_round and fixed_current_round.get("start_time") != None:
        start_time = fixed_current_round.get("start_time")
        if fixed_current_round.get("type") not in ["regular", "reveal", "blind", "song"]:
            start_time = max(start_time - light_round_length, 1.1)
        if start_time is not None:
            return start_time
    length = player.get_length()/1000
    buffer = 10
    need_censors = light_mode in ['regular', 'reveal']
    need_mute_censors = light_mode in ['regular', 'blind', 'song']
    if not need_censors:
        buffer = 1
    if length < (light_round_length+light_round_answer_length+(buffer*2)+1):
        return 1  # If the video is too short, start from 1
    start_time = None
    try_count = 0
    file_censors = get_file_censors(currently_playing.get('filename')) if (need_censors or need_mute_censors) else None
    while start_time is None:
        start_time = random.randrange(buffer, int(length - (light_round_length+light_round_answer_length+buffer)))
        try_count += 1
        if try_count <= 20 and file_censors:
            end_time = start_time + light_round_length
            for censor in file_censors:
                if (((censor.get("mute") or censor.get("skip")) and need_mute_censors) or (not (censor.get("mute") or censor.get("skip")) and need_censors)) and (not (censor['end'] < start_time or censor['start'] > end_time)):
                    start_time = None
                    break
    return start_time

light_speed_modifier = 1
light_blind_one_second_count = None
stream_start_time = 0
current_light_mode = None
current_light_variant = None
_light_answer_wall_start = None  # wall-clock time when the answer phase began (set on first tick)
_light_answer_last_tick  = None  # wall-clock time of last update_light_round call in answer phase (pause compensation)
_wall_time = __import__('time').time  # alias so the 'time' parameter inside update_light_round doesn't shadow it
_showed_lightning_answer = False
def update_light_round(time):
    global light_round_started, light_round_start_time, censors_enabled, light_round_length, light_speed_modifier, light_name_overlay
    global stream_start_time, character_round_answer, character_round_characters, light_blind_one_second_count, current_light_mode
    global _light_answer_wall_start, filter_vf_active, _filter_vf_variant, _showed_lightning_answer
    global _light_answer_last_tick
    # During clip/OST rounds use actual player position relative to stream_start_time.
    # _stream_wall_start is used purely as a sentinel — True once the initial seek has fired.
    # Using player position means the timer naturally pauses when the player is paused.
    if currently_streaming and light_round_start_time is not None:
        if _stream_wall_start is not None:
            elapsed = max(0, player.get_time() / 1000.0 - stream_start_time)
        else:
            elapsed = 0
        time = light_round_start_time + elapsed
    if not light_round_start_time and (light_mode == 'frame' or frame_light_round_started):
        if time < 1 and not frame_light_round_started:
            player.pause()
            setup_frame_light_round()
        return
    if (time > 1 or _light_answer_wall_start is not None) and light_round_start_time != None and light_round_started:
        # Once the wall clock is set we're permanently in the answer phase regardless of Player position
        # (seeking the theme backwards must not flip us back into question-phase logic)
        _in_answer_phase = _light_answer_wall_start is not None or time >= light_round_start_time + light_round_length
        _now = _wall_time()
        if _in_answer_phase and _light_answer_wall_start is None:
            _light_answer_wall_start = _now
            _light_answer_last_tick  = _now
        # Pause compensation: when the player is paused, slide the reference
        # start forward so that _answer_elapsed stays frozen.  Checking
        # player.is_playing() directly is reliable and avoids false positives
        # from OS timer jitter that plagued the old gap-threshold approach.
        if _light_answer_wall_start is not None and _light_answer_last_tick is not None:
            if not player.is_playing():
                _light_answer_wall_start += _now - _light_answer_last_tick
        _light_answer_last_tick = _now
        _answer_elapsed = (_now - _light_answer_wall_start) if _light_answer_wall_start is not None else 0
        if _in_answer_phase and _answer_elapsed >= light_round_answer_length:
            light_round_transition()
        elif _in_answer_phase:
            start_str = "next"
            blind_length = lightning_mode_settings.get("blind", {}).get("length", LIGHT_ROUND_LENGTH_DEFAULT)
            BLIND_ONE_SECOND_TIME = 4
            if light_blind_one_second_count != None and light_blind_one_second_count < blind_length:
                if light_blind_one_second_count % BLIND_ONE_SECOND_TIME == 0:
                    light_blind_one_second_count += 1
                    player.pause()
                    set_progress_overlay(light_round_length*100, light_round_length*100)
                    def update_light_blind_count():
                        global light_blind_one_second_count
                        if not light_blind_one_second_count:
                            return
                        if (light_blind_one_second_count + 1) % BLIND_ONE_SECOND_TIME == 0:
                            player.set_time(round(float(light_round_start_time) * 1000))
                            player.play()
                        light_blind_one_second_count += 1
                        set_countdown(round(blind_length - light_blind_one_second_count))
                    for s in range(BLIND_ONE_SECOND_TIME-1):
                        root.after(1000 * (s+1), update_light_blind_count)
                    set_countdown(round(blind_length - light_blind_one_second_count))
            else:
                if not _showed_lightning_answer:
                    _showed_lightning_answer = True
                    char_answer = copy.copy(character_round_answer)
                    cover_answer = light_cover_image
                    image_answer_source = None  # source text shown as answer (no header, width_max=0.55)
                    if fixed_current_round and fixed_current_round.get("type") == "image":
                        answer_image_url = (fixed_current_round.get("answer_image_url") or "").strip()
                        answer_show_both = fixed_current_round.get("answer_show_both", False)
                        if answer_image_url:
                            try:
                                answer_image = load_image_from_url(answer_image_url, size=None)
                                if answer_show_both:
                                    if light_cover_image:
                                        cover_answer = [light_cover_image, answer_image]
                                    else:
                                        cover_answer = answer_image
                                else:
                                    cover_answer = answer_image
                            except Exception:
                                pass
                            # Collect source text to show as answer instead of the IMAGE SOURCE header
                            if last_image_source[0] == currently_playing.get("filename") and last_image_source[1]:
                                if fixed_current_round.get("image_source"):
                                    image_answer_source = fixed_current_round.get("image_source")
                                else:
                                    src_url = last_image_source[1]
                                    image_answer_source = src_url.split('/')[2] if src_url.startswith('http') else src_url
                    trivia_answer = light_trivia_answer
                    if mismatch_visuals:
                        top_info_data = "MISMATCHED VISUALS:\n" + mismatch_visuals
                    elif (last_streamed[0] == currently_playing.get("filename") and last_streamed[1] and last_streamed[1] != "Trailer"
                            and not (fixed_current_round and fixed_current_round.get("clip_source_as_song"))):
                        top_info_data = f"YOUTUBE VIDEO:\n{last_streamed[1]}\nby {last_streamed[3] or ''}"
                    elif image_answer_source:
                        top_info_data = None  # will be shown via top_info(image_answer_source) below
                    elif last_image_source[0] == currently_playing.get("filename") and last_image_source[1]:
                        if fixed_current_round and fixed_current_round.get("image_source"):
                            domain = fixed_current_round.get("image_source")
                        else:
                            # Extract domain from URL
                            url = last_image_source[1]
                            domain = url.split('/')[2] if url.startswith('http') else url
                        top_info_data = f"IMAGE SOURCE:\n{domain}"
                    else:
                        top_info_data = None
                    if light_mode == 'ost' and not (fixed_current_round and fixed_current_round.get("clip_for_answer")):
                        _show_ost_cover()  # hide video during transition; removed by stop_stream
                    toggle_title_popup(True)
                    set_black_screen(False)
                    update_light_round_number()
                    clean_up_light_round()
                    max_width_size = 0.55 if (light_round_answer_length < 10) else 0.5

                    if synopsis_start_index is not None and fixed_current_round and fixed_current_round.get("overlay_during_answer"):
                        toggle_synopsis_overlay(text=get_light_synopsis_string())
                    if top_info_data:
                        top_info(top_info_data, 20)
                    if char_answer:
                        top_info(char_answer[0], width_max=max_width_size) 
                        toggle_character_image_overlay(char_answer[1])
                    if cover_answer:
                        toggle_character_image_overlay(cover_answer)
                    if trivia_answer:
                        _uses_mc_highlight = (fixed_current_round or {}).get("overlay_during_answer") and _mc_last_choices
                        if _uses_mc_highlight:
                            # Correct answer shown via highlighted MC overlay; show header only
                            _ans_header = (fixed_current_round or {}).get("answer_header", "")
                            if _ans_header:
                                top_info(_ans_header, width_max=max_width_size)
                        else:
                            _ans_header = (fixed_current_round or {}).get("answer_header", "")
                            _ans_display = f"{_ans_header}:\n{trivia_answer}" if _ans_header else trivia_answer
                            top_info(_ans_display, width_max=max_width_size)
                    if image_answer_source:
                        top_info(image_answer_source, width_max=max_width_size)
                    # For clip_for_answer rounds the stream keeps playing during the answer phase.
                    # If clip_replay_for_answer is set, seek back to clip_start_time (or 0) to
                    # replay the clip from the beginning. Otherwise seek forward to where the
                    # answer portion starts (stream_start_time + round_length).
                    if (fixed_current_round and fixed_current_round.get("clip_for_answer")
                            and stream_start_time is not None):
                        if fixed_current_round.get("clip_replay_for_answer"):
                            _replay_target_sec = fixed_current_round.get("clip_start_time") or 0
                            player.set_time(round(_replay_target_sec * 1000))
                            player.play()
                        else:
                            _clip_answer_target_ms = int((stream_start_time + light_round_length) * 1000)
                            if abs(player.get_time() - _clip_answer_target_ms) > 2000:
                                player.set_time(_clip_answer_target_ms)
                    # For fixed rounds where start_time means the theme's answer entry point
                    # (i.e. non-regular/peek/blind/song types), seek the theme to start_time and unmute
                    # so the theme plays during the answer phase regardless of where Player currently is.
                    _seek_types = ["regular", "reveal", "blind", "song"]
                    if (fixed_current_round and fixed_current_round.get("start_time") is not None
                            and fixed_current_round.get("type") not in _seek_types
                            and not fixed_current_round.get("clip_for_answer")):
                        player.set_time(round(fixed_current_round["start_time"] * 1000))
                        player.play()
                        toggle_mute(False, True)
                if not light_mode or (fixed_lightning_round_playlist_data and fixed_lightning_round_playlist_data.get("current_index") == fixed_lightning_round_playlist_data.get("round_count") - 1):
                    start_str = "end"
                set_countdown(start_str + " in..." + str(round(light_round_answer_length - _answer_elapsed)))
        else:
            time_left = (light_round_length-(time - light_round_start_time))
            if time_left < 1 and light_speed_modifier != 1:
                light_speed_modifier = 1
                player.set_rate(light_speed_modifier)
            if current_light_mode == 'song' or song_overlay_boxes:
                show_title_time = light_round_length if not fixed_current_round else fixed_current_round.get("song_title_reveal_time", light_round_length)
                show_artist_time = light_round_length * 0.75 if not fixed_current_round else fixed_current_round.get("song_artist_reveal_time", light_round_length * 0.75)
                show_slug_time = light_round_length * 0.5 if not fixed_current_round else fixed_current_round.get("song_slug_reveal_time", light_round_length * 0.5)
                show_music_time = light_round_length * (1/3) if not fixed_current_round else fixed_current_round.get("song_music_reveal_time", light_round_length * (1/3))
                toggle_song_overlay(show_title=time_left<=show_title_time, show_artist=time_left<=show_artist_time, show_theme=time_left<=show_slug_time, show_music=time_left<=show_music_time)
                player.audio_set_mute(time_left > show_music_time)
                play_background_music(time_left > show_music_time)
            elif _clues_cell_values:
                data = currently_playing.get("data")
                if time_left <= 15:
                    _clues_cell_values["Tags"] = "\n".join(get_tags(data))
                else:
                    _clues_cell_values["Tags"] = f"in...{round(time_left-15)}"
                if time_left <= 10:
                    _clues_cell_values["Episodes"] = get_episode_display(data, suffix="")
                    _clues_cell_values["Score"]    = f"{data.get('score')}\n#{data.get('rank')}"
                    _members_num = _safe_int(data.get('members', 0), 0)
                    _clues_cell_values["Members"]  = f"{_members_num:,}\n#{data.get('popularity') or 'N/A'}"
                else:
                    _clues_cell_values["Episodes"] = f"in...{round(time_left-10)}"
                    _clues_cell_values["Score"]    = f"in...{round(time_left-10)}"
                    _clues_cell_values["Members"]  = f"in...{round(time_left-10)}"
                if time_left <= 5:
                    _clues_cell_values["Song"] = f"{data.get('slug')}: {get_song_string(data)}"
                else:
                    _clues_cell_values["Song"] = f"SONG in...{round(time_left-5)}"
                _draw_clues_canvas()
            elif synopsis_start_index is not None:
                answer_time = 8
                if light_trivia_answer:
                    answer_time = 6
                synopsis_words = get_light_synopsis_string().split(" " if fixed_current_round else None)
                _reveal_speed = fixed_current_round.get("reveal_speed") if fixed_current_round else None
                if _reveal_speed is not None:
                    # reveal_speed = seconds from start at which full text is shown; 0 = show all immediately
                    elapsed = light_round_length - time_left
                    if _reveal_speed <= 0:
                        progress = 1.0
                    else:
                        progress = max(0.0, min(1.0, elapsed / _reveal_speed))
                else:
                    reveal_duration = light_round_length - answer_time
                    if reveal_duration > 0:
                        elapsed = light_round_length - time_left
                        progress = max(0.0, min(1.0, elapsed / reveal_duration))
                    else:
                        progress = 1.0
                word_count = max(1, round(len(synopsis_words) * progress))
                shown_text = " ".join(synopsis_words[:word_count])
                toggle_synopsis_overlay(text=shown_text)
            elif current_light_mode == 'emoji' or emoji_overlay_window:
                # Reveal emojis one by one over the round
                emojis = get_emoji_clues_for_title(currently_playing.get("data"))
                elapsed = light_round_length - max(0, time_left)
                progress = max(0, min(1, elapsed / light_round_length))
                emoji_count = max(1, round(len(emojis) * progress)+1)
                toggle_emoji_overlay(emojis=emojis, max_emojis=emoji_count)
            elif light_progress_bar:
                set_progress_overlay(round((time - light_round_start_time)*100), light_round_length*100)
                if currently_streaming and (not fixed_current_round or fixed_current_round.get("reveal_title_halfway")):
                    half_time = (light_round_length / 2)
                    track_name = extract_track_name_from_youtube_title(last_streamed[1], currently_playing.get("data", {}))
                    if track_name.strip() != "":
                        if time_left >= half_time:
                            bottom_info(f"TRACK NAME in...{round(time_left-half_time)}")
                        else:
                            bottom_info(track_name)
            elif (current_light_mode == 'title' and current_light_variant == 'reveal') or title_overlay:
                if fixed_current_round and fixed_current_round.get("reveal_letter_order"):
                    starting_letters = int(fixed_current_round.get("reveal_starting_count", 0))
                    final_count = len(fixed_current_round.get("reveal_letter_order", "").split(","))
                    reveal_count = final_count - starting_letters
                    interval = reveal_count / 5 if reveal_count > 0 else 1
                else:
                    starting_letters = min(5, max(1, len(title_light_letters) // 5))
                    interval = len(title_light_letters) * 0.09
                    final_count = round((5*interval)+starting_letters)
                word_num = min(final_count, int(((light_round_length-time_left)/3)*interval)+starting_letters)
                bottom_info(f"{word_num}/{final_count} REVEALS", inverse=character_round_answer)
                toggle_title_overlay(get_title_light_string(word_num))
            elif scramble_overlay_root or current_light_variant == 'scramble':
                if fixed_current_round and fixed_current_round.get("scramble_place_order"):
                    order_count = len([x for x in fixed_current_round["scramble_place_order"].split(",") if x.strip().isdigit()])
                    total_letters = min(order_count, len(scramble_overlay_letters))
                else:
                    total_letters = max(1, round(len(scramble_overlay_letters) * 0.45))
                placement_cutoff = light_round_length * (2 / 3)

                if time_left >= light_round_length - placement_cutoff:
                    # We're still in the placement phase
                    elapsed = light_round_length - time_left
                    progress = elapsed / placement_cutoff  # 0 to 1
                    word_num = int(total_letters * progress)
                else:
                    # Final 1/3 — all letters placed, time to guess
                    word_num = total_letters
                bottom_info(f"{word_num}/{total_letters} PLACEMENTS", inverse=character_round_answer)
                toggle_scramble_overlay(num_letters=word_num)
            elif swap_overlay_root or current_light_variant == 'swap':
                # Total swaps you want to show, based on number of pairs
                if len(swap_pairs) <= 2:
                    total_swaps = 0
                else:
                    total_swaps = round(len(swap_pairs) * 0.4)

                # Define the cutoff point — after this, no more swaps
                swap_cutoff = light_round_length * (2 / 3)

                if time_left >= light_round_length - swap_cutoff:
                    # Still in swap phase
                    elapsed = light_round_length - time_left
                    progress = elapsed / swap_cutoff  # 0 to 1
                    word_num = int(total_swaps * progress)
                else:
                    # In the final 1/3 — guessing phase
                    word_num = total_swaps
                bottom_info(f"{word_num}/{total_swaps} SWAPS", inverse=character_round_answer)
                toggle_swap_overlay(num_swaps=word_num)
            elif peek_overlay1:
                gap = get_peek_gap(currently_playing.get("data"))
                toggle_peek_overlay(direction=peek_light_direction, progress=((light_round_length-time_left)/light_round_length)*100, gap=gap)
                now_playing_background_music(music_files[current_music_index])
            elif edge_overlay_box:
                edge_max = max(15, min(70, (currently_playing.get("data").get('popularity') or 3000)/12))
                progress = (light_round_length - time_left) / light_round_length
                block_percent = 100 - (edge_max * progress)  # from 100% to 80%
                toggle_edge_overlay(block_percent=block_percent)
                now_playing_background_music(music_files[current_music_index])
            elif grow_overlay_boxes:
                grow_max = max(20, min(60, (currently_playing.get("data").get('popularity') or 3000)/10))
                progress = (light_round_length - time_left) / light_round_length
                block_percent = 100 - (grow_max * progress)  # from 100% to 80%
                toggle_grow_overlay(block_percent=block_percent, position=grow_position)
                now_playing_background_music(music_files[current_music_index])
            elif filter_vf_active:
                progress = (light_round_length - time_left) / light_round_length
                progress = min(max(progress, 0.0), 1.0)
                toggle_filter_vf(_filter_vf_variant, progress)
                _update_filter_intensity_bottom_label(_filter_vf_variant, progress)
                now_playing_background_music(music_files[current_music_index])
            elif character_overlay_boxes:
                reveal_num = min(4, (int(light_round_length - (time_left)) // (light_round_length // 4)) + 1)
                toggle_character_overlay(num_characters=reveal_num)
                bottom_info(f"{reveal_num}/{4}", inverse=character_round_answer)
            elif character_image_overlay:
                _update_character_image_overlay()
            elif character_pixel_overlay:
                total_steps = len(character_pixel_images)
                step_num = min(total_steps-1, (int(light_round_length - (time_left)) // (light_round_length // total_steps)))
                toggle_character_pixel_overlay(step=step_num)
                bottom_info(f"{step_num+1}/{total_steps}", inverse=character_round_answer)
            elif blur_reveal_image_window:
                progress = (light_round_length - max(0, time_left)) / light_round_length
                progress = min(max(progress, 0.0), 1.0)
                blur_percent = 100 - (100 * progress)
                toggle_character_blur_reveal_overlay(percent=blur_percent / 100, destroy=False)
                bottom_info(f"BLUR: {round(blur_percent)}%", inverse=character_round_answer)
            elif zoom_reveal_image_window:
                progress = ((light_round_length - 1) - max(0, time_left-1)) / (light_round_length-1)
                progress = min(max(progress, 0.0), 1.0)
                zoom_percent = 100 - (100 * progress)
                toggle_character_zoom_reveal_overlay(percent=zoom_percent / 100, destroy=False)
                bottom_info(f"ZOOM OUT: {round(100 - zoom_percent)}%", inverse=character_round_answer)
            elif slice_overlay_window:
                progress = (light_round_length - max(0, time_left-1)) / light_round_length
                progress = min(max(progress, 0.0), 1.0) 
                total_parts = len(slice_overlay_parts) // 2
                slices_to_show = max(1, min(total_parts, round(total_parts * progress)))
                toggle_slice_overlay(num_revealed=slices_to_show)
                bottom_info(f"{slices_to_show}/{total_parts}", inverse=character_round_answer)
            elif tile_overlay_window:
                if not tile_overlay_swap:
                    progress = (light_round_length - max(0, time_left-1)) / light_round_length
                    progress = min(max(progress, 0.0), 1.0) 
                    total_parts = len(tile_overlay_parts) // 2
                    tiles_to_show = max(1, min(total_parts, round(total_parts * progress)))
                    toggle_tile_overlay(num_revealed=tiles_to_show)
                    bottom_info(f"{tiles_to_show}/{total_parts}", inverse=character_round_answer)
                else:
                    # Swap tiles one by one over the round
                    total_swaps = len(tile_overlay_parts) // 4
                    elapsed = light_round_length - max(0, time_left)
                    progress = max(0, min(1, elapsed / light_round_length))
                    swaps_to_show = max(1, round(total_swaps * progress))
                    toggle_tile_overlay(num_revealed=swaps_to_show, swap=True)
                    bottom_info(f"{swaps_to_show}/{total_swaps} SWAPS", inverse=character_round_answer)
            elif reveal_image_window:
                progress = (light_round_length - max(0, time_left-1)) / light_round_length
                progress = min(max(progress, 0.0), 1.0)
                block_percent = 100 - (100 * progress)
                toggle_character_reveal_overlay(percent=block_percent / 100, destroy=False)
            elif profile_overlay_window:
                bio_text = character_round_answer[3]
                total_words = 70 #len(bio_text.split())

                progress = (light_round_length - time_left) / light_round_length

                # Reveal bio over the first 10 seconds
                max_bio_time = 12
                if time_left > light_round_length - max_bio_time:
                    partial = 1 - ((time_left - (light_round_length - max_bio_time)) / max_bio_time)
                    words_to_show = int(partial * total_words)
                else:
                    words_to_show = total_words

                # Show image in last 5 seconds
                image_countdown = max(0, int(time_left - 3))

                # Call the toggle
                toggle_character_profile_overlay(word_count=words_to_show, image_countdown=image_countdown)
                if image_countdown > 0:
                    bottom_info(f"IMAGE IN {image_countdown}...", inverse=True)
                else:
                    bottom_info()
            elif tag_cloud_tags:
                starting_tags = 1
                final_count = len(tag_cloud_tags)
                time_left_t = time_left - 5
                light_round_length_t = light_round_length - 5

                # Use the actual light round length
                progress = (light_round_length_t - time_left_t) / (light_round_length_t)
                progress = max(0, min(progress, 1))  # Clamp between 0 and 1

                # Calculate how many tags to show
                tags_num = min(final_count, int(progress * final_count) + starting_tags)

                # Update overlay and label
                bottom_info(f"{tags_num}/{final_count}")
                toggle_tag_cloud_overlay(tags_num)
            elif light_episode_names:
                total_eps = min(len(light_episode_names), 6)
                reveal_num = min(6, (int(light_round_length - time_left) // (light_round_length // total_eps)) + 1)
                toggle_episode_overlay(reveal_num)
                bottom_info(f"{reveal_num}/{total_eps}", inverse=character_round_answer)
            if edge_overlay_box:
                set_countdown(round(time_left/light_speed_modifier), position="center")
            elif light_blind_one_second_count is not None:
                blind_length = lightning_mode_settings.get("blind", {}).get("length", LIGHT_ROUND_LENGTH_DEFAULT)
                set_countdown(round(blind_length - light_blind_one_second_count))
            else:
                set_countdown(round(time_left/light_speed_modifier), inverse=character_round_answer)
    if light_mode and _light_answer_wall_start is None:
        if time < 1:
            toggle_coming_up_popup(False, "Lightning Round")
        if not light_round_started and time < 1:
            light_round_started = True
            _showed_lightning_answer = False
            current_light_mode = light_mode
            if lightning_mode_settings.get("_misc_settings", {}).get("framed_video"):
                root.after(300, set_video_frame, True)
            if light_mode in ['regular', 'reveal']:
                root.after(500, set_black_screen, False)
            def set_double_speed():
                global light_round_length, light_speed_modifier
                light_speed_modifier = 2
                player.set_rate(light_speed_modifier)
                light_round_length = light_round_length * light_speed_modifier
                bottom_info(f"x{light_speed_modifier} SPEED")
            def set_one_second():
                global light_round_length, light_blind_one_second_count
                light_blind_one_second_count = 0
                light_round_length = 1
                bottom_info(f"ONE SECOND")
            if light_round_start_time is None:
                light_round_start_time = get_light_round_time()
            if lightning_mode_settings.get(light_mode, {}).get("muted"):
                toggle_mute(True)
            if light_mode == 'blind':
                if fixed_current_round:
                    blind_mode = fixed_current_round.get("blind_variant", "standard")
                    if fixed_current_round.get("blind_header"):
                        top_info(fixed_current_round.get("blind_header"))
                else:
                    blind_variants = lightning_mode_settings.get("blind",{}).get("variants",{})
                    standard, double_speed, mismatch, one_second = blind_variants.get("standard"), blind_variants.get("double_speed"), blind_variants.get("mismatch"), blind_variants.get("one_second")
                    blind_modes = ['standard', 'standard', 'standard', 'mismatch']
                    allowed_blind_modes = []
                    for m in blind_modes:
                        if blind_variants.get(m):
                            allowed_blind_modes.append(m)
                    # Only fall back to the full list for non-mismatch modes; mismatch
                    # requires its own setup and shouldn't be selected unless enabled.
                    allowed_blind_modes = allowed_blind_modes or [m for m in blind_modes if m != 'mismatch']
                    blind_mode = random.choice(allowed_blind_modes)
                if blind_mode == "mismatch":
                    # Explicitly init the round here — the mismatch seek moves the
                    # player past position 1s so the normal time < 1 gate won't fire.
                    if not light_round_started:
                        light_round_started = True
                        set_progress_overlay(0, light_round_length * 100)
                    # Mute the player directly (not toggle_mute — that triggers background music)
                    # so the theme audio doesn't play from position 0 while we load the
                    # mismatch video and seek to light_round_start_time.
                    player.audio_set_mute(True)
                    def _start_mismatch_after_theme(theme_path):
                        global _mismatch_active, _mismatch_vid_track_id, _mismatch_orig_vid
                        if currently_playing.get("filename") != _cur_fn:
                            player.audio_set_mute(False)
                            return
                        if not theme_path:
                            player.audio_set_mute(False)
                            return
                        # Add the mismatch video as an external track on the main player.
                        # Stay paused through video-add AND the seek so mpv's internal
                        # sync operations don't interrupt the audio pipeline.
                        try:
                            _mismatch_orig_vid = player._p.vid
                            _was_paused = player._p.pause
                            if not _was_paused:
                                player._p.pause = True
                            player._p.command('video-add', theme_path, 'select')
                            # Seek to round start while still paused — no audio disruption
                            try:
                                player._p.seek(float(light_round_start_time), 'absolute')
                            except Exception:
                                pass
                            # Find the newly added external video track ID
                            _mismatch_vid_track_id = None
                            try:
                                tracks = player._p.track_list or []
                                ext_vids = [t for t in tracks if t.get('type') == 'video' and t.get('external')]
                                if ext_vids:
                                    _mismatch_vid_track_id = ext_vids[-1].get('id')
                            except Exception:
                                pass
                            # Always unpause — we want the round playing regardless of initial state
                            player._p.pause = False
                        except Exception as e:
                            print(f"[mismatch] exception in video-add block: {e}")
                            player.audio_set_mute(False)
                            return
                        # Unmute now that we're at the right position with the right video
                        player.audio_set_mute(False)
                        set_volume(volume_level)
                        _mismatch_active = True
                        spawn_pulsating_music_note()
                        set_black_screen(False)
                        top_info("MISMATCHED VISUALS")
                        bottom_info("GUESS BY MUSIC ONLY")
                        update_light_round_number()
                    _cur_fn = currently_playing.get("filename")
                    def _theme_worker():
                        theme_path = directory_files.get(get_mismatched_theme())
                        root.after(0, _start_mismatch_after_theme, theme_path)
                    threading.Thread(target=_theme_worker, daemon=True).start()
                else:
                    if not fixed_current_round:
                        is_op = is_slug_op(currently_playing.get('data', {}).get('slug', ""))
                        def pick_double_or_one_second(is_op):
                            if double_speed and one_second:
                                if not is_op or random.randint(1, 2) == 1:
                                    return "double_speed"
                                else:
                                    return "one_second"
                            elif double_speed:
                                return "double_speed"
                            elif one_second:
                                return "one_second"
                        if double_speed or one_second:
                            if not standard:
                                blind_mode = pick_double_or_one_second(is_op)
                            else:
                                popularity = currently_playing.get("data", {}).get("popularity", 1000) or 3000
                                if (popularity <= 100 and random.randint(1, 3) == 1) or (popularity <= 250 and random.randint(1, 6) == 1):
                                    blind_mode = pick_double_or_one_second(is_op)
                    if blind_mode == "double_speed":
                        set_double_speed()
                    elif blind_mode == "one_second":
                        set_one_second()
                    set_progress_overlay(0, light_round_length*100)
            elif light_mode == 'clues':
                toggle_clues_overlay()
            elif light_mode == 'song':
                toggle_song_overlay(show_title=False, show_artist=False, show_theme=False, show_music=False)
            elif light_mode == 'synopsis':
                pick_synopsis()
                toggle_synopsis_overlay(text=get_light_synopsis_string(words = 1))
            elif light_mode == 'trivia':
                trivia_data = lightning_queue_data.get(currently_playing.get("filename", {}), {}).get("trivia", [])
                set_light_trivia(trivia_data=trivia_data)
                toggle_synopsis_overlay(text=get_light_synopsis_string(words = 1))
            elif light_mode == "emoji":
                toggle_emoji_overlay(max_emojis=1)
            elif light_mode == 'title':
                start_title_round()
                top_header = ""
                if fixed_current_round:
                    top_header = fixed_current_round.get("title_header", "")
                else:
                    top_header = "MUST SAY FULL TITLE"
                top_info(top_header.upper())
            elif light_mode == 'reveal':
                send_scoreboard_command("hide")
                peek_mode = get_next_peek_mode()
                if peek_mode == 'edge':
                    toggle_edge_overlay()
                elif peek_mode == 'grow':
                    set_grow_position()
                    toggle_grow_overlay(position=grow_position)
                elif peek_mode == 'slice':
                    choose_peek_direction()
                    toggle_peek_overlay()
                elif peek_mode in ('blur', 'outline', 'pixelize', 'wave', 'zoom'):
                    filter_vf_active = True
                    _filter_vf_variant = peek_mode
                    toggle_filter_vf(peek_mode, 0)
            elif light_mode == 'character':
                character_round_characters = lightning_queue_data.get(currently_playing.get("filename", {}), {}).get("characters", [])
                if not character_round_characters:
                    get_character_round_characters()
                toggle_character_overlay(num_characters=1)
                top_info("CHARACTERS")
            elif light_mode in ['cover', 'image']:
                header = ""
                reveal_mode = ""
                if light_mode == 'cover':
                    get_light_cover_image()
                    if fixed_current_round:
                        header = fixed_current_round.get("cover_header", "")
                        reveal_mode = fixed_current_round.get("image_variant", "standard")
                    else:
                        header = "COVER ART"
                        reveal_mode = get_next_cover_reveal_mode()
                elif light_mode == 'image':
                    get_light_image_from_google()
                    if fixed_current_round:
                        header = fixed_current_round.get("image_header", "")
                        reveal_mode = fixed_current_round.get("image_variant", "standard")
                    else:
                        header = "RANDOM IMAGE"
                        reveal_mode = get_next_image_reveal_mode()
                fixed_round = fixed_current_round or {}
                slide_direction = fixed_round.get("slide_direction", "top")
                slice_count = fixed_round.get("slice_count", 10)
                slice_vertical = fixed_round.get("slice_vertical", True)
                tile_grid_size = fixed_round.get("tile_grid_size", 4)
                top_info(header.upper())
                apply_reveal_mode(reveal_mode, 
                                    image_source=ImageTk.getimage(light_cover_image).convert("RGBA"),
                                    slide_direction=slide_direction,
                                    slice_vertical=slice_vertical,
                                    slice_count=slice_count,
                                    tile_grid_size=tile_grid_size)
            elif 'c.' in light_mode:
                top_info("GUESS THE CHARACTER", inverse=True)
                character_round_answer = lightning_queue_data.get(currently_playing.get("filename", {}), {}).get("character_answer")
                if not character_round_answer:
                    min_desc = 0
                    if light_mode == 'c. profile':
                        min_desc = 120
                    get_character_round_image(types=get_char_types_by_popularity(mode=light_mode), min_desc_length=min_desc)
                if light_mode == 'c. reveal':
                    c_reveal_mode = get_next_c_reveal_mode()
                    if c_reveal_mode == 'parts':
                        get_char_parts_round_character()
                        toggle_character_overlay(num_characters=1)
                    else:
                        apply_reveal_mode(c_reveal_mode, slice_vertical=False)
                elif light_mode == 'c. profile':
                    toggle_character_profile_overlay()
                elif light_mode == 'c. name':
                    top_info("MUST SAY FULL NAME", inverse=True)
                    start_title_round()
                if lightning_mode_settings.get(light_mode).get("muted"):
                    now_playing_background_music(track = None)
                    toggle_mute(True)
            elif light_mode == 'tags':
                set_cloud_tags()
                top_info("TAGS")
                toggle_tag_cloud_overlay(1)
            elif light_mode == 'episodes':
                set_light_episodes()
                toggle_episode_overlay(1)
                if fixed_current_round:
                    top_header = fixed_current_round.get("episodes_header", "")
                else:
                    top_header = "EPISODE TITLES"
                top_info(top_header.upper())
            elif light_mode == 'names':
                light_name_overlay = True
                set_light_names()
                toggle_episode_overlay(1)
                top_info("CHARACTER NAMES")
            elif light_mode in ['clip', 'ost']:
                _always_dl_clip = ffmpeg_available and lightning_mode_settings.get("_misc_settings", {}).get("always_download_clip", False)
                def _ensure_clip_downloaded(yt_url):
                    """If always_download_clip is on and the file isn't cached, start the download then show the wait popup."""
                    if not (yt_url and _always_dl_clip):
                        return
                    cache_path = _get_yt_cache_path(yt_url)
                    if not cache_path or (os.path.exists(cache_path) and not os.path.exists(cache_path + '.part')):
                        return  # already cached (or no video ID) — nothing to do
                    # Start download if not already running
                    vid_match = re.search(r'(?:v=|youtu\.be/|/embed/)([a-zA-Z0-9_-]{11})', yt_url)
                    vid_id = vid_match.group(1) if vid_match else None
                    if vid_id and vid_id not in youtube_control._yt_cache_downloads_in_progress:
                        cache_mb = int(lightning_mode_settings.get("_misc_settings", {}).get("download_cache_mb", 0))
                        effective_mb = cache_mb if cache_mb > 0 else 500
                        threading.Thread(
                            target=_yt_cache_download_bg,
                            args=(yt_url, cache_path, effective_mb),
                            daemon=True
                        ).start()
                    _yt_cache_wait_popup(yt_url)
                if fixed_current_round:
                    url, name, channel = fixed_current_round.get("clip_url"), fixed_current_round.get("clip_title"), fixed_current_round.get("clip_author")
                    _ensure_clip_downloaded(url)
                    length = stream_url(url, name, channel)
                else:
                    clip_variants = lightning_mode_settings.get("clip", {}).get("variants", {})
                    clip_enabled, trailer_enabled = clip_variants.get("random_clip"), clip_variants.get("trailer")
                    length = 0
                    is_ost = (light_mode == 'ost')
                    if is_ost:    
                        url = lightning_queue_data.get(currently_playing.get("filename", {}), {}).get("ost_url")
                    else:
                        url = lightning_queue_data.get(currently_playing.get("filename", {}), {}).get("clip_url")
                    if not url:
                        if not youtube_api_limited and YOUTUBE_API_KEY and (clip_enabled or is_ost):
                            length = play_random_clip(ost=is_ost)
                        elif currently_playing.get("data", {}).get("trailer") and trailer_enabled and is_ost:
                            length = play_trailer()
                    elif trailer_enabled and url[1] == 'trailer':
                        length = play_trailer()
                    else:
                        _ensure_clip_downloaded(url[0])
                        length = stream_url(url[0], url[1], url[2])
                if currently_streaming:
                    # Compute start time now if we have a known length; otherwise defer until player is ready
                    if length > 0:
                        stream_start_time = get_stream_start_time(length)
                    else:
                        _cst = fixed_current_round.get("clip_start_time") if fixed_current_round else None
                        stream_start_time = max(0, _cst) if _cst is not None else 0
                    test_print(f"Length: {length} | Stream Start Time: {stream_start_time}")
                    # player is already loading the stream (set_media called in stream_url)
                    test_print(currently_streaming)
                    def wait_for_stream(filename, count):
                        global stream_start_time, _stream_wall_start
                        test_print(F"Waiting...{count}")
                        def restart_player():
                            player.stop()
                            player.play()
                            root.after(100, wait_for_stream, filename, 0)
                        if filename != currently_playing.get("filename") or not currently_streaming:
                            return
                        elif player.is_playing() and player.get_length() > 0:
                            # If length was unknown when stream started, calculate start time now
                            actual_length = player.get_length() / 1000
                            _cst = fixed_current_round.get("clip_start_time") if fixed_current_round else None
                            if stream_start_time == 0 and not (fixed_current_round and _cst is not None):
                                stream_start_time = get_stream_start_time(actual_length)
                                test_print(f"Deferred stream start time: {stream_start_time} (length={actual_length})")
                            def stream_overlay():
                                global black_overlay
                                if _light_answer_wall_start is not None or not light_round_started:
                                    return  # answer phase already started — don't re-apply overlays
                                if light_mode == 'ost':
                                    # Per-round framed_video override (fixed rounds only)
                                    _framed_ost = (fixed_current_round.get("framed_video")
                                                   if fixed_current_round and fixed_current_round.get("framed_video") is not None
                                                   else False)
                                    if _framed_ost and not _video_frame_active:
                                        set_video_frame(True)
                                    if not black_overlay:  # already up — skip re-application
                                        set_black_screen(True)  # OST is audio-only; hide video with blind overlay
                                    _top_font_size_ost = 80
                                    if fixed_current_round and fixed_current_round.get("ost_header"):
                                        top_info(fixed_current_round.get("ost_header").upper(), _top_font_size_ost)
                                    else:
                                        top_info("SOUNDTRACK / OST", _top_font_size_ost)
                                else:
                                    # Clear the blind that play_filename raised before the clip loaded
                                    # Per-round framed_video override (fixed rounds); falls back to global framed_video_clip
                                    _framed_clip = (fixed_current_round.get("framed_video")
                                                    if fixed_current_round and fixed_current_round.get("framed_video") is not None
                                                    else lightning_mode_settings.get("_misc_settings", {}).get("framed_video_clip"))
                                    if _framed_clip and not _video_frame_active:
                                        set_video_frame(True)
                                    set_black_screen(False)
                                    _top_font_size = 80 if _framed_clip else 40
                                    if (fixed_current_round and fixed_current_round.get("censor_bottom")) or (not fixed_current_round and last_streamed[3] and "Crunchyroll" in last_streamed[3]):
                                        toggle_outer_edge_overlay()
                                    if fixed_current_round and fixed_current_round.get("clip_header"):
                                        top_info(fixed_current_round.get("clip_header").upper(), _top_font_size)
                                    elif last_streamed[1] == "Trailer":
                                        top_info("TRAILER", _top_font_size)
                                    else:
                                        top_info("RANDOM CLIP", _top_font_size)
                                update_light_round_number()
                            def set_stream_start():
                                global _stream_wall_start, black_overlay
                                # For OST rounds raise the blind immediately so the video is
                                # never visible; stream_overlay will confirm it later.
                                if light_mode == 'ost' and not black_overlay:
                                    set_black_screen(True)
                                player.set_time(round(float(stream_start_time) * 1000))
                                # Mark seek as done — update_light_round uses this as a sentinel.
                                _stream_wall_start = True
                                # Unmute now so the stream is audible immediately on seek.
                                toggle_mute(False, True)
                                # Initialise the OST progress bar exactly once right here so it
                                # starts from 0 without any later stream_overlay call resetting it.
                                if light_mode == 'ost':
                                    set_progress_overlay(0, light_round_length*100)
                                volume_adjustment = fixed_current_round.get("volume_adjustment", 0) if fixed_current_round else 0
                                _stream_volume_level = int(volume_level * (1 + ((stream_volume_boost + volume_adjustment) / 100)))
                                player.audio_set_volume(_stream_volume_level)
                            def start_player():
                                if filename != currently_playing.get("filename") or not currently_streaming:
                                    return
                                if _light_answer_wall_start is not None or not light_round_started:
                                    return  # answer phase already started — don't interfere
                                target_ms = round(float(stream_start_time) * 1000)
                                current_ms = player.get_time()
                                test_print(f"start_player check: current={current_ms} target={target_ms}")
                                # If the player is more than 2.5 s behind the target the seek
                                # didn't take (stream playing from 0).  Re-attempt once.
                                if player.is_playing() and current_ms < target_ms - 2500:
                                    test_print(f"Seek miss — retrying seek to {target_ms}")
                                    player.set_time(target_ms)
                                    def _check_retry():
                                        if filename != currently_playing.get("filename") or not currently_streaming:
                                            return
                                        if player.is_playing() and player.get_time() < target_ms - 2500:
                                            test_print("Seek retry failed — restarting stream")
                                            restart_player()
                                    root.after(2000, _check_retry)
                                # else: playing from (approximately) the right position
                            root.after(2000, start_player)
                            set_stream_start()
                            for time in [500, 1000, 1500, 2000]:
                                root.after(time, stream_overlay)
                        elif count >= 5000:
                            restart_player()
                        else:
                            count += 100
                            root.after(100, wait_for_stream, filename, count)
                    wait_for_stream(currently_playing.get("filename"), 0)
                else:
                    if last_variety_forced:
                        variety_mode_cooldown_counts['clip'] = rnd_data.get("variety", {}).get("cooldown", {}).get("max_gap", 0)
                    toggle_mute(False)
                    root.after(500, set_black_screen, False)
            # Auto-trigger MC bonus if this fixed round defines MC choices
            if fixed_current_round and fixed_current_round.get("mc_choice_2"):
                guess_extra("fixed_mc")
            append_lightning_history()
            set_countdown(int(light_round_length), inverse=character_round_answer)
            update_light_round_number(inverse=character_round_answer)
        if not currently_streaming and light_round_started and _light_answer_wall_start is None:
            #only if not already at time (skip during answer phase — answer seek may target an earlier position)
            if light_round_start_time is not None and projected_player_time < round(float(light_round_start_time) * 1000):
                player.set_time(round(float(light_round_start_time) * 1000))

def apply_reveal_mode(reveal_mode, image_source=None, slide_direction=None, slice_vertical=None, slice_count=None, tile_grid_size=None):
    """
    Apply a reveal mode overlay with the specified parameters.
    
    Args:
        reveal_mode: The reveal mode type ('pixel', 'slide', 'blur', 'zoom', 'slice', 'tile', 'swap')
        image_source: PIL Image for pixel mode, or None to use character_round_answer image
        slide_direction: Direction for slide mode ('top', 'bottom', 'left', 'right'), or None for random/default
        slice_vertical: Bool for slice orientation, or None for random
        slice_count: Number of slices, or None for default
        tile_grid_size: Grid size for tiles, or None for default
    """
    if reveal_mode == 'standard':
        char_answer = copy.copy(character_round_answer)
        cover_answer = light_cover_image
        if char_answer:
            toggle_character_image_overlay(char_answer[1])
        elif cover_answer:
            toggle_character_image_overlay(cover_answer)
    elif reveal_mode == 'pixel':
        if image_source:
            generate_pixelation_steps(pil_image=image_source)
        else:
            generate_pixelation_steps()
        toggle_character_pixel_overlay()
    elif reveal_mode == 'slide':
        if slide_direction:
            toggle_character_reveal_overlay(direction=slide_direction)
        else:
            toggle_character_reveal_overlay(direction=random.choice(['top','bottom','left','right']))
    elif reveal_mode == 'blur':
        toggle_character_blur_reveal_overlay(percent=1.0)
    elif reveal_mode == 'zoom':
        toggle_character_zoom_reveal_overlay(percent=1.0)
    elif reveal_mode == 'slice':
        vertical = slice_vertical if slice_vertical is not None else random.choice([True, False])
        if slice_count:
            toggle_slice_overlay(num_revealed=1, num_slices=slice_count, vertical=vertical)
        else:
            toggle_slice_overlay(num_revealed=1, vertical=vertical)
    elif reveal_mode == 'tile':
        grid_size = tile_grid_size if tile_grid_size else 5
        toggle_tile_overlay(num_revealed=1, grid_size=grid_size)
    elif reveal_mode == 'swap':
        toggle_tile_overlay(grid_size=10, swap=True)

