def _fmt_pt(v):
    """Format a point value as a display string, e.g. 1.0 → '1 PT', 2.0 → '2 PTs'."""
    n = int(v) if v == int(v) else v
    return f"{n} PT" if v <= 1 else f"{n} PTs"
