SYSTEM_PLAYLISTS = ['Tagged Themes', 'Favorite Themes', 'New Themes', 'Missing Artists', 'Blind Themes', 'Reveal Themes', 'Mute Reveal Themes']

def get_playlist(playlist_name):
    playlist_path = os.path.join(PLAYLISTS_FOLDER, f"{playlist_name}.json")
    if os.path.exists(playlist_path):
        with open(playlist_path, "r", encoding="utf-8") as f:
            return json.load(f)
    else:
        new_playlist = copy.deepcopy(BLANK_PLAYLIST)
        new_playlist["name"] = playlist_name
        return new_playlist

def _push_web_marks(filename=None):
    """Push the current theme's mark states to all web host clients."""
    if not web_server.is_running():
        return
    fn = filename or currently_playing.get("filename") or ""
    web_server.push_marks({
        "tagged":    bool(check_theme(fn, "Tagged Themes")),
        "favorited": bool(check_theme(fn, "Favorite Themes")),
        "blind":     bool(check_theme(fn, "Blind Themes")),
        "peek":      bool(check_theme(fn, "Reveal Themes")),
        "mute_peek": bool(check_theme(fn, "Mute Reveal Themes")),
    })

def _push_web_toggles():
    """Push current toggle states to all web host clients."""
    if not web_server.is_running():
        return
    if not fixed_lightning_rounds_list:
        load_fixed_lightning_rounds(filter_missing_themes=True)
    fn = currently_playing.get("filename", "")
    _all_censors = get_file_censors(fn) or [] if fn else []
    censor_count      = sum(1 for c in _all_censors if not c.get('nsfw'))
    censor_nsfw_count = sum(1 for c in _all_censors if c.get('nsfw'))
    mute_state = light_muted if (light_mode or light_round_started) else disable_video_audio
    scoreboard_open = bool(is_scoreboard_running())
    scoreboard_visible = bool(scoreboard_open and (scoreboard_control.visible_hint is not False))
    web_server.push_toggles({
        "blind":        black_overlay is not None,
        "reveal":         bool(is_peek_active()),
        "mute":         bool(mute_state),
        "censors":      censors_enabled,
        "censors_nsfw": censors_nsfw_enabled,
        "shortcuts":    not disable_shortcuts,
        "dock":         bool(is_docked()),
        "info_start":   bool(auto_info_start),
        "info_end":     bool(auto_info_end),
        "info_popup":   bool(_title_popup_intent and not title_info_only),
        "title_popup":  bool(_title_popup_intent and title_info_only),
        "artist_popup": bool(_title_popup_intent and artist_info_display),
        "studio_popup": bool(_title_popup_intent and studio_info_display),
        "season_popup": bool(_title_popup_intent and season_info_display),
        "year_popup":   bool(_title_popup_intent and year_info_display),
        "censor_count": censor_count,
        "censor_nsfw_count": censor_nsfw_count,
        "queue_blind":   bool(blind_round_toggle),
        "queue_reveal":    bool(peek_round_toggle),
        "queue_mute_reveal": bool(mute_peek_round_toggle),
        "queued_peek_variant": _queued_peek_variant[0] or "",
        "live_peek_variant": (
            "slice" if peek_overlay1
            else "edge" if edge_overlay_box
            else "grow" if grow_overlay_boxes
            else (_filter_vf_variant or "") if filter_vf_active
            else ""
        ),
        "light_mode":    light_mode or "",
        "has_fixed_lightning": bool(fixed_lightning_rounds_list),
        "has_youtube":   bool(youtube_metadata.get("videos")),
        "yt_queued":     bool(youtube_queue),
        "fl_queued":     bool(fixed_lightning_queue),
        "fl_active":     bool(fixed_lightning_round_playlist_data),
        "search_queued": bool(search_queue),
        "difficulty":    playlist.get("difficulty", 2),
        "auto_bonus_start": auto_bonus_start,
        "active_bonus": guessing_extra,
        "end_session_popup": bool(end_message_window),
        "scoreboard_open": scoreboard_open,
        "scoreboard_visible": scoreboard_visible,
        "session_history_count": get_themes_played_count(),
        "selected_rules_file": selected_rules_file,
        "selected_light_mode_settings": selected_light_mode_settings,
        "autoplay_fullscreen": bool(autoplay_fullscreen),
        "bonus_menu_visibility": {
            t: bonus_settings.get(t, {}).get("show_in_menu", True)
            for t in ("freeform", "buzzer", "multiple", "year", "score", "members",
                      "popularity", "tags", "studio", "artist", "song", "characters")
        },
        "reveal_variant_menu_visibility": dict(
            lightning_mode_settings.get("reveal", {}).get("show_in_menu", {})
        ),
    })

def toggle_theme(playlist_name, filename=None, quiet=False, add=False):
    """Toggles a theme in a specified playlist (e.g., Tagged Themes, Favorite Themes)."""
    if not filename:
        if currently_playing.get("filename"):
            filename = currently_playing.get("filename")
        else:
            return
        
    playlist_path = os.path.join(PLAYLISTS_FOLDER, f"{playlist_name}.json")
    # Load or initialize the playlist
    data = get_playlist(playlist_name)
    theme_list = data["playlist"]

    type_string = "saved to"
    if filename in theme_list:
        if not add:
            # Remove theme
            theme_list.remove(filename)
            type_string = "removed from"
        else:
            return
    else:
        # Add theme
        if not theme_list:
            theme_list = [filename]
        else:
            theme_list.append(filename)

    # Save the updated playlist
    data["playlist"] = theme_list

    if not os.path.exists(PLAYLISTS_FOLDER):
        os.makedirs(PLAYLISTS_FOLDER)

    _atomic_json_write(playlist_path, data, indent=4)
    if not quiet:
        print(f"{filename} {type_string} playlist '{playlist_name}'.")

    if playlist.get("name") == playlist_name:
        if filename in theme_list:
            if filename not in playlist["playlist"]:
                playlist["playlist"].append(filename)
            # Update current index to end of playlist
            if currently_playing.get("filename") == filename:
                playlist["current_index"] = len(playlist["playlist"]) - 1
            update_current_index()
        else:
            if filename in playlist["playlist"]:
                playlist["playlist"].remove(filename)
                if currently_playing.get("filename") == filename:
                    playlist["current_index"] -= 1
                    update_current_index()

    check_theme(playlist_name=playlist_name, recache=True)

    if currently_playing.get('filename') == filename and web_server.is_running():
        _push_web_marks(filename)

    if currently_playing.get("data") and currently_playing.get('filename') == filename:
        update_series_song_information(currently_playing.get("data"), currently_playing.get("data").get("mal"))

    if playlist_name == "Favorite Themes" and currently_playing.get('filename') == filename and is_title_window_up() and not title_info_only:
        toggle_title_popup(True)

check_theme_cache = {}
def check_theme(filename=None, playlist_name=None, recache=False):
    """Checks if a theme exists in a specified playlist (e.g., Tagged Themes, Favorite Themes)."""
    global check_theme_cache
    if playlist_name and (recache or not check_theme_cache.get(playlist_name)):
        playlist_path = os.path.join(PLAYLISTS_FOLDER, f"{playlist_name}.json")
        if os.path.exists(playlist_path):
            with open(playlist_path, "r", encoding="utf-8") as f:
                loaded_data = json.load(f)
                # Convert infinity markers (though only using playlist array, good practice)
                loaded_data = convert_infinity_markers(loaded_data)
                check_theme_cache[playlist_name] = set(loaded_data.get("playlist", []))
        else:
            check_theme_cache[playlist_name] = set()
    return filename in check_theme_cache.get(playlist_name, set())

