undock_position = []
dock_was_minimized = False
player_collapsed = False
original_window_height = None
original_min_height = None

def toggle_player_collapse():
    """Collapses or expands the player info columns."""
    global player_collapsed, collapse_button, original_window_height, original_min_height
    
    player_collapsed = not player_collapsed
    
    if player_collapsed:
        # Store the original window height and min height before collapsing
        if original_window_height is None:
            original_window_height = root.winfo_height()
            original_min_height = root.minsize()[1]
        
        # Get the info panel height before hiding it
        info_panel_height = info_panel.winfo_height()
        
        # Hide the info panel entirely
        info_panel.pack_forget()
        
        # Update window to force geometry recalculation
        root.update_idletasks()
        
        # Adjust window height and minimum height
        new_height = original_window_height - info_panel_height
        new_min_height = original_min_height - info_panel_height
        root.minsize(scl(900, "UI"), new_min_height)
        root.geometry(f"{root.winfo_width()}x{new_height}")
        
        # If docked, reposition the window to the bottom
        if is_docked():
            move_root_to_bottom()
        
        collapse_button.config(text="▲")
    else:
        # Show the info panel again in the right position (after first_row_frame)
        info_panel.pack(after=first_row_frame, fill="both", expand=True, padx=scl(10, "UI"), pady=scl(5, "UI"))
        
        # Restore original window height and min height if we have it
        if original_window_height is not None:
            root.geometry(f"{root.winfo_width()}x{original_window_height}")
        if original_min_height is not None:
            root.minsize(scl(900, "UI"), original_min_height)
        
        # If docked, reposition the window to the bottom
        if is_docked():
            move_root_to_bottom()
        
        collapse_button.config(text="▼")

def dock_player():
    """Toggles the Tkinter window between front and back, moves it to bottom left,
    adjusts transparency, and removes the title bar when brought forward."""
    global undock_position, dock_was_minimized
    button_seleted(dock_button, not is_docked())
    if is_docked():
        # Send to back, restore transparency, and re-enable title bar
        root.attributes("-topmost", False)
        # root.overrideredirect(False)  # Restore title bar
        root.attributes("-alpha", 1.0)  # Make fully visible
        if not disable_shortcuts:
            move_root_to_bottom(False)
        elif undock_position[1] < root.winfo_y():
            root.after(10, lambda: root.geometry(f"+{undock_position[0]}+{undock_position[1]}"))
        # Re-minimize if the window was minimized before docking
        if dock_was_minimized:
            dock_was_minimized = False
            root.iconify()
    else:
        # Remember if the window was minimized, then restore it so we can move it
        dock_was_minimized = root.state() == 'iconic'
        if dock_was_minimized:
            root.deiconify()
        # Bring to front, move to bottom-left, set full transparency, and remove title bar
        right_top.delete(1.0, tk.END)
        undock_position = (root.winfo_x(), root.winfo_y())
        # root.overrideredirect(True)  # Remove title bar
        root.attributes("-alpha", 0.8)  # Set transparency to 80%
        root.attributes("-topmost", True)
        move_root_to_bottom()
        root.lift()
    up_next_text()
    # Refresh list display to adjust button count based on right_top content changes
    if list_loaded:
        refresh_current_list()

def move_root_to_bottom(toggle=True):
    """Moves the Tkinter root window to the bottom-left corner with accurate positioning."""
    root.update_idletasks()  # Ensure correct window size calculations

    screen_width = root.winfo_screenwidth()
    screen_height = root.winfo_screenheight()
    window_width = root.winfo_width()
    window_height = root.winfo_height()

    taskbar_height = 0  
    y_position = screen_height - window_height - taskbar_height
    x_position = screen_width/2 - window_width/2 - taskbar_height

    # Ensure y is never negative
    y_position = max(0, y_position)
    x_position = int(max(0, x_position))
    # Set exact position (left edge at x=0)
    if not toggle:
        root.after(1, lambda: animate_window(root, x_position, screen_height))
    else:
        root.geometry(f"+{x_position}+{screen_height}")  # Adjust for bottom spacing
        root.after(10, lambda: animate_window(root, x_position, y_position-30))

def is_docked():
    return root.attributes("-topmost")

def popup_menu(menu, x, y):
    """Show a tk.Menu at (x, y), ensuring it appears on top when the player is docked.

    When docked the root has -topmost True, which causes native Win32 menu windows
    (#32768) to appear behind it.  We temporarily drop topmost before tk_popup
    (which blocks until the menu is dismissed) and restore it immediately after.
    """
    docked = is_docked()
    if docked:
        root.attributes("-topmost", False)
    try:
        menu.tk_popup(x, y)
    finally:
        menu.grab_release()
        if docked:
            root.attributes("-topmost", True)

def get_window_position_and_setup(window=None, set_topmost_if_docked=True, offset_x=0, offset_y=0):
    """
    Get the root window position and optionally set window attributes based on docked state.
    
    Args:
        window: Optional Toplevel window to configure. If provided, will set geometry and topmost attribute.
        set_topmost_if_docked: If True and window is provided, sets topmost when root is docked.
        offset_x: Optional x-axis offset from root window position.
        offset_y: Optional y-axis offset from root window position.
    
    Returns:
        tuple: (x, y) position of root window (after applying offset)
    """
    root.update_idletasks()
    x = root.winfo_x() + offset_x
    y = root.winfo_y() + offset_y
    
    if window:
        window.update_idletasks()
        window.geometry(f"+{x}+{y}")
        
        # Set topmost if root is docked
        if set_topmost_if_docked and is_docked():
            window.attributes("-topmost", True)
        
        window.lift()
        window.focus_force()
    
    return (x, y)

