#            *KEYBOARD SHORTCUTS
# =========================================

disable_shortcuts = True

def _is_blocked_text_entry():
    """Return True if any Entry widget currently has keyboard focus.
    Pynput should be blocked whenever an Entry is focused — the toolbar search
    bar handles its own keys via Tkinter <KeyRelease>, and pynput-based search
    mode (list_loaded == 'search') is only active when no Entry is focused.
    Must be called from the main Tkinter thread."""
    try:
        focused = root.focus_get()
        return focused is not None and isinstance(focused, tk.Entry)
    except Exception:
        return False

def on_press(key):
    def _handle(key=key):
        global disable_shortcuts, modal_dialog_open
        try:
            if modal_dialog_open:
                return
            if _is_blocked_text_entry():
                return
            if disable_shortcuts:
                pass
            elif grow_overlay_boxes:
                move_amount = 10  # pixels per key press
                if key == key.up:
                    move_grow_position(0, -move_amount)
                elif key == key.down:
                    move_grow_position(0, move_amount)
                elif key == key.left:
                    move_grow_position(-move_amount, 0)
                elif key == key.right:
                    move_grow_position(move_amount, 0)
            elif key == key.up:
                list_move(-1)
            elif key == key.down:
                list_move(1)
        except AttributeError:
            try:
                if list_loaded == "search":
                    pass
                elif not playlist.get("infinite", False) and (key.char == '-'):
                    player.set_time(player.get_time()-1000)
                elif not playlist.get("infinite", False) and (key.char == '+'):
                    player.set_time(player.get_time()+1000)
            except AttributeError as e:
                print(f"Error: {e}")
    try:
        root.after(0, _handle)
    except RuntimeError:
        pass

def on_release(key):
    def _handle(key=key):
        global disable_shortcuts, modal_dialog_open
        try:
            if modal_dialog_open:
                return
            if _is_blocked_text_entry():
                return
            if popout_searching:
                pass
            elif disable_shortcuts:
                try:
                    enable_key = get_shortcut("enable_shortcuts")
                    if enable_key and key.char == enable_key:
                        cmd = _shortcut_dispatch.get(enable_key)
                        if cmd:
                            cmd()
                        else:
                            toggle_disable_shortcuts()  # fallback before dispatch is built
                except:
                    pass
            elif list_loaded in ["search", "search_add"]:
                global search_term
                if key == keyboard.Key.esc:
                    search(add=playlist.get("infinite", False))
                elif key == keyboard.Key.backspace:
                    if search_term != "":
                        search_term = search_term[:-1]
                    search(True, add=playlist.get("infinite", False))
                elif key == keyboard.Key.space:
                    search_term = search_term + " "
                    search(True, add=playlist.get("infinite", False))
                elif key == keyboard.Key.enter:
                    list_select()
                    search_term = ""
                    list_unload(right_column)
                elif isinstance(key, keyboard.KeyCode) and key.char:
                    search_term = search_term + key.char
                    search(True, add=playlist.get("infinite", False))
            else:
                if isinstance(key, keyboard.Key):
                    if not grow_overlay_boxes:
                        if key == keyboard.Key.right:
                            play_next()
                        elif key == keyboard.Key.left:
                            play_previous()
                    if key == keyboard.Key.space:
                        play_pause()
                    elif key == keyboard.Key.esc:
                        stop()
                    elif key == keyboard.Key.tab:
                        player.toggle_fullscreen()
                    elif key == keyboard.Key.backspace:
                        if (peek_overlay1 or edge_overlay_box or grow_overlay_boxes):
                            toggle_peek()
                        else:
                            blind(True)
                    elif key == keyboard.Key.enter:
                        list_select()
                elif isinstance(key, keyboard.KeyCode) and key.char:
                    # --- Registry-driven dispatch ---
                    # Covers all shortcuts defined in DEFAULT_SHORTCUTS (or user overrides).
                    # Context-sensitive and aliased keys are handled below.
                    cmd = _shortcut_dispatch.get(key.char)
                    if cmd:
                        root.after(0, cmd)
                    # --- 'i' has context-sensitive logic: shows info OR clears title popup ---
                    elif key.char == 'i':
                        if is_title_window_up() and (artist_info_display or studio_info_display):
                            toggle_title_popup(True)
                        else:
                            toggle_info_popup()
                    # --- '+' is a secondary alias for '=' (peek toggle), not in DEFAULT_SHORTCUTS ---
                    elif key.char == '+':
                        toggle_peek()
                    # --- Digits: context-sensitive (list select vs seek position) ---
                    elif key.char.isdigit():
                        if list_loaded and list_loaded != "playlist":
                            global list_index
                            list_index = int(key.char)-1
                            list_select()
                        else:
                            seek_value = player.get_length()-((player.get_length()/10)*(10-int(key.char)))
                            seek_to(int(seek_value))
                    # --- Infinite difficulty adjust (condition-gated, not suitable for registry) ---
                    elif playlist.get("infinite") and (key.char in ['<',',']):
                        if playlist["difficulty"] > 0:
                            playlist["difficulty"] -= 1
                            difficulty_dropdown.current(playlist["difficulty"])
                            select_difficulty()
                    elif playlist.get("infinite") and (key.char in ['>','.']):
                        if playlist["difficulty"] < len(difficulty_options)-1:
                            playlist["difficulty"] += 1
                            difficulty_dropdown.current(playlist["difficulty"])
                            select_difficulty()
        except AttributeError as e:
            print(f"Error: {e}")
    try:
        root.after(0, _handle)
    except RuntimeError:
        pass

# Mouse state tracking
mouse_left_pressed = False
mouse_dragging_grow_overlay = False
mouse_dragging_zoom_filter = False
target_mouse_position = None
animation_after_id = None
zoom_filter_animation_after_id = None

def smooth_move_zoom_filter_overlay():
    """Smoothly animate the zoom crop centre toward the target mouse position."""
    global zoom_filter_animation_after_id, _filter_vf_last
    if not mouse_dragging_zoom_filter or not target_mouse_position:
        zoom_filter_animation_after_id = None
        return
    tx, ty = target_mouse_position
    # Normalise relative to the mpv player window so windowed mode works correctly
    try:
        mx, my, mw, mh = _get_mpv_window_rect()
    except Exception:
        mx, my, mw, mh = 0, 0, root.winfo_screenwidth(), root.winfo_screenheight()
    if mw <= 0 or mh <= 0:
        mx, my, mw, mh = 0, 0, root.winfo_screenwidth(), root.winfo_screenheight()
    norm_x = (tx - mx) / mw - 0.5
    norm_y = (ty - my) / mh - 0.5
    norm_x = max(-0.45, min(0.45, norm_x))
    norm_y = max(-0.45, min(0.45, norm_y))
    lerp = 0.15
    _filter_zoom_offset[0] += (norm_x - _filter_zoom_offset[0]) * lerp
    _filter_zoom_offset[1] += (norm_y - _filter_zoom_offset[1]) * lerp
    # force cache miss so vf is actually updated
    _filter_vf_last = None
    try:
        toggle_filter_vf(_filter_vf_variant, _filter_vf_last_progress[0])
    except Exception:
        pass
    dist = ((norm_x - _filter_zoom_offset[0])**2 + (norm_y - _filter_zoom_offset[1])**2) ** 0.5
    if mouse_dragging_zoom_filter and dist > 0.003:
        zoom_filter_animation_after_id = root.after(16, smooth_move_zoom_filter_overlay)
    else:
        zoom_filter_animation_after_id = None

def smooth_move_grow_overlay():
    """Smoothly animate the grow overlay toward the target mouse position."""
    global grow_position, target_mouse_position, animation_after_id
    
    if not mouse_dragging_grow_overlay or not target_mouse_position:
        animation_after_id = None
        return
    
    current_x, current_y = grow_position if grow_position else (0, 0)
    raw_target_x, raw_target_y = target_mouse_position

    # Convert screen coordinates to OSD (mpv client area) coordinates
    try:
        mpv_ox, mpv_oy, mpv_ow, mpv_oh = _get_mpv_window_rect()
    except Exception:
        mpv_ox, mpv_oy = 0, 0
    osd_target_x = raw_target_x - mpv_ox
    osd_target_y = raw_target_y - mpv_oy
    
    lerp_factor = 0.15  # Adjust this value: lower = smoother/slower, higher = faster
    new_x = current_x + (osd_target_x - current_x) * lerp_factor
    new_y = current_y + (osd_target_y - current_y) * lerp_factor
    
    # Update position
    grow_position = (int(new_x), int(new_y))
    toggle_grow_overlay(block_percent=last_grow_block_percent, position=grow_position)
    
    distance = ((osd_target_x - new_x) ** 2 + (osd_target_y - new_y) ** 2) ** 0.5
    if mouse_dragging_grow_overlay and distance > 2:  # Stop when very close
        animation_after_id = root.after(16, smooth_move_grow_overlay)  # ~60 FPS
    else:
        animation_after_id = None

# Mouse event handlers
def on_mouse_click(x, y, button, pressed):
    """Handle mouse click events."""
    global mouse_left_pressed, mouse_dragging_grow_overlay, mouse_dragging_zoom_filter, target_mouse_position, animation_after_id, zoom_filter_animation_after_id, last_seek_time, can_seek
    
    if pressed:
        if button == mouse.Button.left:
            mouse_left_pressed = True
            if grow_overlay_boxes:
                mx, my, mw, mh = _get_mpv_window_rect()
                if mx <= x < mx + mw and my <= y < my + mh:
                    mouse_dragging_grow_overlay = True
                    target_mouse_position = (x, y)
                    if animation_after_id is None:
                        smooth_move_grow_overlay()
            elif filter_vf_active and _filter_vf_variant == 'zoom':
                mx, my, mw, mh = _get_mpv_window_rect()
                if mx <= x < mx + mw and my <= y < my + mh:
                    mouse_dragging_zoom_filter = True
                    target_mouse_position = (x, y)
                    if zoom_filter_animation_after_id is None:
                        smooth_move_zoom_filter_overlay()
        
        elif button == mouse.Button.right:
            widen_peek()
    else:
        if button == mouse.Button.left:
            mouse_left_pressed = False
            mouse_dragging_grow_overlay = False
            mouse_dragging_zoom_filter = False
            target_mouse_position = None
            # Cancel animation
            if animation_after_id:
                root.after_cancel(animation_after_id)
                animation_after_id = None
            if last_seek_time:
                seek_time = int(float(last_seek_time)) * 1000
                seek_to(seek_time)
                last_seek_time = None
                def clear_last_seek_time():
                    global last_seek_time
                    last_seek_time = None
                root.after(100, clear_last_seek_time)
        # Add your mouse release handling logic here

def on_mouse_move(x, y):
    """Handle mouse move events - set target position for smooth animation."""
    global target_mouse_position
    
    # If left mouse is pressed and we're dragging the grow overlay
    if mouse_dragging_grow_overlay and mouse_left_pressed:
        mx, my, mw, mh = _get_mpv_window_rect()
        if mx <= x < mx + mw and my <= y < my + mh:
            target_mouse_position = (x, y)
            if animation_after_id is None:
                smooth_move_grow_overlay()
    elif mouse_dragging_zoom_filter and mouse_left_pressed:
        mx, my, mw, mh = _get_mpv_window_rect()
        if mx <= x < mx + mw and my <= y < my + mh:
            target_mouse_position = (x, y)
            if zoom_filter_animation_after_id is None:
                smooth_move_zoom_filter_overlay()

